template<typename T>
int nStage2dDWT(T *in, T *out, T *backup, int pixWidth, int pixHeight, int stages, bool forward)
{
    if (forward)
    {
        fdwt(in, out, pixWidth, pixHeight, stages);
    }
    else
    {
        rdwt(out, in, pixWidth, pixHeight, stages);
    }
    return 0;
}

