void samplesToChar(unsigned char *dst, float *src, int samplesNum)
{
    int i;

    for (i = 0; i < samplesNum; i++)
    {
        float r = (src[i] + 0.5f) * 255;
        if (r > 255) r = 255;
        if (r < 0) r = 0;
        dst[i] = (unsigned char)r;
    }
}

void samplesToChar(unsigned char *dst, int *src, int samplesNum)
{
    int i;

    for (i = 0; i < samplesNum; i++)
    {
        int r = src[i] + 128;
        if (r > 255) r = 255;
        if (r < 0) r = 0;
        dst[i] = (unsigned char)r;
    }
}

template<typename T>
int writeLinear(T *component_cuda, int pixWidth, int pixHeight, const char *filename, const char *suffix)
{
    int samplesNum = pixWidth * pixHeight;
    int size = samplesNum * sizeof(T);

    T *gpu_output = (T *)malloc(size);
    unsigned char *result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(gpu_output, component_cuda, size, cudaMemcpyDeviceToHost);

    samplesToChar(result, gpu_output, samplesNum);

    char outfile[strlen(filename) + strlen(suffix) + 1];
    strcpy(outfile, filename);
    strcpy(outfile + strlen(filename), suffix);

    int i = open(outfile, O_CREAT | O_WRONLY, 0644);
    if (i == -1)
    {
        error(0, errno, "cannot access %s", outfile);
        return -1;
    }

    write(i, result, samplesNum);
    close(i);

    free(gpu_output);
    free(result);

    return 0;
}

